{
  "title": "सेल्फ-बैलेंसिंग सर्च ट्रीज़",
  "group": "ट्री डेटा स्ट्रक्चर्स",
  "options": [
    {
      "text": "बाइनरी सर्च ट्री और मिनिमम हीप",
      "hint": "क्या ये दोनों ऑटोमैटिक बैलेंसिंग सपोर्ट करते हैं?"
    },
    {
      "text": "AVL ट्री और रेड-ब्लैक ट्री",
      "hint": "इनमें से एक गणितज्ञ के नाम पर है, दूसरा रंगों पर।"
    },
    {
      "text": "मिनिमम हीप और मैक्सिमम हीप",
      "hint": "हीप्स प्रायोरिटी क्यू के लिए होते हैं, बैलेंसिंग के लिए नहीं।"
    },
    {
      "text": "स्टैक और क्यू",
      "hint": "ये लीनियर डेटा स्ट्रक्चर्स हैं, ट्री नहीं।"
    }
  ],
  "questionProse": [
    "इनमें से किस सेट में सेल्फ-बैलेंसिंग बाइनरी सर्च ट्रीज़ के सही उदाहरण दिए गए हैं?"
  ],
  "explanationProse": [
    "AVL ट्री और रेड-ब्लैक ट्री सेल्फ-बैलेंसिंग ट्री के प्रकार हैं। ये हर इन्सर्शन या डिलीशन के बाद ऑटोमैटिकली रोटेशन या री-कलरिंग के ज़रिए ट्री की हाइट को कम रखते हैं, जिससे सर्च, इन्सर्ट और डिलीट ऑपरेशन्स हमेशा O(log n) टाइम में पूरे होते हैं।"
  ]
}
